import base64, ast
open('pacing/calendar.py','wb').write(base64.b64decode(''))
ast.parse(open('pacing/calendar.py').read())
open('db/connection.py','wb').write(base64.b64decode(''))
# Fix db/__init__.py
init = open('db/__init__.py').read()
init = init.replace('from .connection import get_conn, get_pool', 'from .connection import get_conn')
open('db/__init__.py','w').write(init)
print('Installed:')
print('  pacing/calendar.py — DB retry + start from today + full month')
print('  db/connection.py   — fresh connections with keepalives, no pool')
print('  db/__init__.py     — removed get_pool import')
print()
print('Redeploy web deployment, then type generate calendar in Slack')
